module dram_cell(  
    input wire clk,  
    input wire reset,  
    input wire we,  
    input wire re,  
    input wire [15:0] data_in,  
    output reg [15:0] data_out  
);  
    reg [15:0] cell_data;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            cell_data <= 16'b0;  
            data_out <= 16'b0;  
        end else if (we) begin  
            cell_data <= data_in;  
        end else if (re) begin  
            data_out <= cell_data;  
        end  
    end  
endmodule
